import {
    Link,
    useNavigate
}

from "react-router-dom";

function Navbar() {

    const navigate =
        useNavigate();

    const token =
        localStorage.getItem(
            "token"
        );

    const adminToken =
        localStorage.getItem(
            "adminToken"
        );

    const handleLogout = () => {

        localStorage.removeItem(
            "token"
        );

        localStorage.removeItem(
            "customerId"
        );

        localStorage.removeItem(
            "adminToken"
        );

        alert(
            "Logout Successful"
        );

        navigate("/login");
    };

    return (

        <div
            style={{
                backgroundColor:
                    "black",

                padding: "15px",

                display: "flex",

                gap: "20px"
            }}
        >

            <Link
                to="/"

                style={{
                    color: "white",

                    textDecoration:
                        "none"
                }}
            >

                Home

            </Link>

            {
                !token &&
                !adminToken && (

                    <>
                        <Link
                            to="/register"

                            style={{
                                color: "white",

                                textDecoration:
                                    "none"
                            }}
                        >

                            Register

                        </Link>

                        <Link
                            to="/login"

                            style={{
                                color: "white",

                                textDecoration:
                                    "none"
                            }}
                        >

                            Login

                        </Link>

                        <Link
                            to="/admin-login"

                            style={{
                                color: "white",

                                textDecoration:
                                    "none"
                            }}
                        >

                            Admin Login

                        </Link>
                    </>
                )
            }

            {
                token && (

                    <Link
                        to="/my-bookings"

                        style={{
                            color: "white",

                            textDecoration:
                                "none"
                        }}
                    >

                        My Bookings

                    </Link>
                )
            }

            {
                adminToken && (

                    <Link
                        to="/admin-dashboard"

                        style={{
                            color: "white",

                            textDecoration:
                                "none"
                        }}
                    >

                        Admin Dashboard

                    </Link>
                )
            }

            {
                (token || adminToken) && (

                    <button

                        onClick={handleLogout}

                        style={{
                            backgroundColor:
                                "red",

                            color: "white",

                            border: "none",

                            padding:
                                "5px 10px",

                            cursor:
                                "pointer"
                        }}
                    >

                        Logout

                    </button>
                )
            }

        </div>
    );
}

export default Navbar;
